SELECT COALESCE(SUM(amount), 0)
FROM transactions
WHERE user_id = #{userId}
  AND transaction_type = 'INCOME'
  AND transaction_date BETWEEN #{startDate} AND #{endDate}

SELECT COALESCE(SUM(amount), 0)
FROM transactions
WHERE user_id = #{userId}
  AND transaction_type = 'EXPENSE'
  AND transaction_date BETWEEN #{startDate} AND #{endDate}
